// Build a mock classified-alert payload based on the
// intraday_classified_alert contract (workflows/contracts/intraday_classified_alert.json),
// with an additional derived date_key field for downstream smoke-test writes.
// date_key is NOT part of the base contract (additionalProperties: false there)
// but is derived from event_at by the pipeline before the D1 write step.
//
// Edit topic_slug and headline below to test different topics.
const now = new Date().toISOString();
const dateKey = now.slice(0, 10); // YYYY-MM-DD

return [{
  json: {
    item_id:          'smoke-test-' + Date.now(),
    topic_slug:       'crypto',
    secondary_topics: ['finance'],
    headline:         '[Smoke Test] Alert write-flow verification — ' + now,
    summary_text:     'Synthetic alert inserted by the local smoke test workflow to verify that the n8n → Cloudflare D1 write path is functioning correctly.',
    source_url:       'https://example.com/smoke-test',
    source_name:      'Smoke Test',
    severity_score:   50,
    importance_score: 65,
    confidence_score: 99,
    send_alert:       true,
    alert_reason:     'Local smoke test — not a real event.',
    event_at:         now,
    cluster_label:    'Smoke Test',
    date_key:         dateKey
  }
}];

// Validate the pipeline payload (contract + pipeline-derived fields)
// before attempting any D1 writes.
// Note: cluster_label is required by the contract but may be null;
// date_key is derived by the pipeline and not part of the base contract.
const item = $input.first().json;

const requiredFields = [
  'item_id', 'topic_slug', 'headline', 'summary_text', 'source_name',
  'severity_score', 'importance_score', 'confidence_score',
  'send_alert', 'event_at', 'date_key'
];

const missing = requiredFields.filter(
  f => item[f] === undefined || item[f] === null || item[f] === ''
);
if (missing.length > 0) {
  throw new Error(
    'Mock alert payload is missing required fields: ' + missing.join(', ')
  );
}

// cluster_label is required by the contract but may be null.
// When null, the write step falls back to topic_slug (matching module 07).
if (item.cluster_label === undefined) {
  throw new Error('cluster_label must be present in the payload (may be null).');
}

const validTopics = ['crypto', 'finance', 'economy', 'health', 'ai', 'energy', 'technology'];
if (!validTopics.includes(item.topic_slug)) {
  throw new Error('Invalid topic_slug: ' + item.topic_slug);
}

if (!/^\d{4}-\d{2}-\d{2}$/.test(item.date_key)) {
  throw new Error('Invalid date_key format (expected YYYY-MM-DD): ' + item.date_key);
}

const scoreFields = ['severity_score', 'importance_score', 'confidence_score'];
const invalidScoreField = scoreFields.find(field => {
  const value = item[field];
  return !Number.isInteger(value) || value < 0 || value > 100;
});

if (invalidScoreField) {
  throw new Error(
    'Invalid score field ' + invalidScoreField + ': received ' + JSON.stringify(item[invalidScoreField]) + '. Score fields must be integers between 0 and 100.'
  );
}

return [$input.first()];

