// Extract the cluster_id returned by the upsert and merge it
// back with the original alert payload from Validate Payload.
const d1Response = $input.item.json;
const clusterId = d1Response?.result?.[0]?.results?.[0]?.id || null;
const alert = $('Validate Payload').item.json;
return [{ json: { ...alert, cluster_id: clusterId } }];

// Extract the D1-assigned alert ID and merge it back with the
// alert payload carried forward from Extract Cluster ID.
const d1Response = $input.item.json;
const alertId = d1Response?.result?.[0]?.results?.[0]?.id || null;
const alert = $('Extract Cluster ID').item.json;
return [{ json: { ...alert, alert_id: alertId } }];

