  json: {
    alert_id:            alert.alert_id,
    cluster_id:          alert.cluster_id,
    topic_slug:          alert.topic_slug,
    date_key:            alert.date_key,
    headline:            alert.headline,
    event_at:            alert.event_at,
    daily_status_ok:     dailyStatusOk
  }
}];

