// Produce a human-readable smoke test result summary.
// A SUCCESS result means the alert was written AND read back from D1.
// The console.log output appears in the n8n execution log.

const d1ReadBack = $input.first().json;
const writeResults = $('Collect Write Results').first().json;
const readRow = d1ReadBack?.result?.[0]?.results?.[0] || null;

const writeOk = writeResults.alert_id !== null;
const readOk  = readRow !== null && readRow.id === writeResults.alert_id;

let status, message;
if (writeOk && readOk) {
  status  = 'SUCCESS';
  message = '✅ Alert written to D1 and confirmed via read-back.';
} else if (writeOk && !readOk) {
  status  = 'WARNING';
  message = '⚠️  Alert was written (ID=' + writeResults.alert_id + ') but read-back returned no matching row. Check D1 consistency.';
} else {
  status  = 'FAILURE';
  message = '❌ Alert write failed — no alert_id was returned by the INSERT step.';
}

const siteBase = $vars.LOCAL_SITE_URL || 'http://localhost:8788';
const timelineUrl = `${siteBase}/${writeResults.topic_slug}/${writeResults.date_key}`;
const apiUrl      = `${siteBase}/api/timeline/${writeResults.topic_slug}/${writeResults.date_key}`;

const summary = {
  status,
  message,
  alert_id:            writeResults.alert_id,
  cluster_id:          writeResults.cluster_id,
  topic_slug:          writeResults.topic_slug,
  date_key:            writeResults.date_key,
  headline:            writeResults.headline,
  event_at:            writeResults.event_at,
  daily_status_ok:     writeResults.daily_status_ok,
  d1_read_back_ok:     readOk,
  site_timeline_page:  timelineUrl,
  api_timeline_url:    apiUrl,
  next_step:           readOk
    ? `Open ${timelineUrl} in a browser (requires wrangler pages dev with remote D1, or your deployed site).`
    : 'Investigate the D1 write error in the execution log above.'
};

console.log(JSON.stringify(summary, null, 2));
return [{ json: summary }];
